/**
 * Send a notification through the appropriate adapter.
 *
 * Calls are queued internally so that concurrent sends are dispatched
 * sequentially, preserving the order in which they were requested. This
 * prevents out-of-order delivery when multiple domain events fire at once.
 *
 * @param input - Notification details. Channel defaults to 'email'.
 * @returns The created NotificationRecord with delivery status.
 */
async send(input: CreateNotificationInput): Promise<NotificationRecord> {
  // Chain onto the send queue so dispatches execute one at a time.
  const sendOp = this.sendQueue.then(() => this.dispatchNotification(input));

  // Update the queue tail. `catch` swallows errors so one failed delivery
  // doesn't block subsequent notifications.
  this.sendQueue = sendOp.catch(() => {});

  return sendOp;
}

/**
 * Internal dispatch — does the real work of building the record, checking
 * preferences, calling the adapter, and emitting lifecycle events.
 *
 * MUST only be called through send() to respect the ordering queue.
 */
private async dispatchNotification(input: CreateNotificationInput): Promise<NotificationRecord> {
  const channel = input.channel ?? 'email';
  const priority = input.priority ?? 'normal';

  const payload: NotificationPayload = {
    type: input.type,
    recipient: input.recipient,
    subject: input.subject,
    body: input.body,
    channel,
    priority,
    metadata: input.metadata,
  };

  // Check user preferences before sending (if preferences service is configured).
  // The recipient may be an email address or a userId; we check both as the
  // userId in metadata (set by event handlers) and the recipient itself.
  const recipientUserId = (input.metadata?.['userId'] as string | undefined) ?? input.recipient;
  if (this.preferencesService) {
    const shouldSend = this.preferencesService.shouldSendNotification(
      recipientUserId,
      channel,
      input.type,
    );
    if (!shouldSend) {
      this.logger.info(
        `Notification suppressed by user preferences: ${input.type} for ${recipientUserId} via ${channel}`,
      );
      // Return a record with 'suppressed' info but do not dispatch.
      const suppressedRecord: NotificationRecord = {
        id: generateNotificationId(),
        type: input.type,
        channel,
        recipient: input.recipient,
        subject: input.subject,
        body: input.body,
        status: 'failed',
        priority,
        metadata: { ...input.metadata, suppressedByPreferences: true },
        createdAt: new Date(),
        failureReason: 'Suppressed by user notification preferences',
      };
      this.notifications.push(suppressedRecord);
      return suppressedRecord;
    }
  }

  const record: NotificationRecord = {
    id: generateNotificationId(),
    type: input.type,
    channel,
    recipient: input.recipient,
    subject: input.subject,
    body: input.body,
    status: 'pending',
    priority,
    metadata: input.metadata,
    createdAt: new Date(),
  };

  const adapter = this.adapters.get(channel);
  if (!adapter) {
    record.status = 'failed';
    record.failureReason = `No adapter registered for channel: ${channel}`;
    this.logger.warn(record.failureReason);
    this.notifications.push(record);

    await this.eventBus.emit({
      type: 'notification:failed',
      notification: record,
      reason: record.failureReason,
      timestamp: new Date(),
    });

    return record;
  }

  // Dispatch to the adapter
  let result: NotificationResult;
  try {
    result = await adapter.send(payload);
  } catch (error) {
    // Adapters should not throw, but handle it gracefully if they do
    const reason = error instanceof Error ? error.message : 'Unknown adapter error';
    result = {
      success: false,
      notificationId: record.id,
      channel,
      failureReason: reason,
    };
  }

  // Update record based on result
  result.notificationId = record.id;
  if (result.success) {
    record.status = 'sent';
    record.sentAt = new Date();
  } else {
    record.status = 'failed';
    record.failureReason = result.failureReason;
  }

  this.notifications.push(record);

  // Emit lifecycle event
  if (record.status === 'sent') {
    await this.eventBus.emit({
      type: 'notification:sent',
      notification: record,
      timestamp: new Date(),
    });
  } else {
    await this.eventBus.emit({
      type: 'notification:failed',
      notification: record,
      reason: record.failureReason ?? 'Unknown error',
      timestamp: new Date(),
    });
  }

  this.logger.info(
    `Notification ${record.id} ${record.status} via ${channel} to ${record.recipient}`,
  );

  return record;
}

